import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testGetCommentMarker() {
        // Given
        Character expected = null; // Default value in CSVFormat.DEFAULT

        // When
        Character actual = csvFormat.getCommentMarker();

        // Then
        assertEquals(expected, actual);
    }

    @Test
    public void testSetCommentMarker() throws Exception {
        // Given
        Character commentMarker = '#';

        // When
        csvFormat.withCommentMarker(commentMarker);
        Character actual = (Character) getPrivateField(csvFormat, "commentMarker");

        // Then
        assertEquals(commentMarker, actual);
    }

    // Helper method to access private fields using reflection
    private Object getPrivateField(Object object, String fieldName) throws Exception {
        java.lang.reflect.Field field = object.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        return field.get(object);
    }
}
